  /* PANEL SOLO VER CONTRATO + RESUMEN DE NÓMINA */
  .view-overlay{
    pointer-events:none;
    position:fixed;
    top:0;
    right:0;
    bottom:0;
    left:var(--sidebar-w);
    width:calc(100vw - var(--sidebar-w));
    background:rgba(2,13,7,.42);
    backdrop-filter:blur(5px);
    z-index:90;
    display:none;
    justify-content:flex-end;
  }
  .view-overlay.open{
    pointer-events:auto;
    display:flex;
  }
  .view-drawer{
    width:430px;
    max-width:calc(100vw - 18px);
    height:100vh;
    background:#fff;
    box-shadow:-22px 0 60px rgba(0,0,0,.22);
    overflow-y:auto;
    animation:viewSlide .22s ease both;
  }
  @keyframes viewSlide{from{transform:translateX(100%)}to{transform:translateX(0)}}
  .view-head{
    height:64px;
    padding:0 22px;
    border-bottom:1px solid var(--border);
    display:flex;
    align-items:center;
    justify-content:space-between;
    position:sticky;
    top:0;
    background:#fff;
    z-index:2;
  }
  .view-title{font-family:'Syne',sans-serif;font-size:21px;font-weight:800;color:var(--text)}
  .view-close{width:34px;height:34px;border:1px solid var(--border);border-radius:11px;background:#fff;cursor:pointer;display:flex;align-items:center;justify-content:center}
  .view-close svg{width:18px;height:18px;stroke:var(--text-mid);fill:none;stroke-width:2}
  .view-body{padding:22px}
  .view-worker{display:flex;align-items:center;gap:14px;padding-bottom:18px;margin-bottom:18px;border-bottom:1px solid var(--border)}
  .view-avatar{width:54px;height:54px;min-width:54px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:'Syne',sans-serif;font-weight:800;color:#fff;font-size:16px;box-shadow:0 10px 22px rgba(0,0,0,.16)}
  .view-worker-name{font-size:17px;font-weight:900;color:var(--text);line-height:1.18}
  .view-worker-sub{font-size:12.5px;color:var(--text-soft);margin-top:4px}
  .view-section{margin-bottom:20px}
  .view-section-title{font-size:11px;font-weight:900;letter-spacing:1.5px;text-transform:uppercase;color:#008c3b;padding-bottom:9px;margin-bottom:12px;border-bottom:1px solid rgba(45,223,110,.18)}
  .view-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}
  .view-card{background:#fbfdfb;border:1px solid var(--border);border-radius:14px;padding:12px}
  .view-card.full{grid-column:1/-1}
  .view-label{font-size:10.5px;font-weight:800;color:var(--text-soft);text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px}
  .view-value{font-size:13.5px;font-weight:800;color:var(--text);word-break:break-word}
  .nomina-box{background:#f7fffa;border:1px solid rgba(45,223,110,.28);border-radius:18px;padding:15px}
  .nomina-row{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:7px 0;font-size:13.5px;color:var(--text-mid)}
  .nomina-row strong{color:var(--text);font-weight:900}
  .nomina-row.deduction strong{color:#ef4444}
  .nomina-row.total{border-top:1px solid rgba(45,223,110,.28);margin-top:8px;padding-top:13px;font-size:15px;font-weight:900;color:var(--text)}
  .nomina-row.total strong{font-family:'Syne',sans-serif;color:#128a3d;font-size:18px}
  .nomina-note{font-size:11px;color:var(--text-soft);line-height:1.35;margin-top:10px}
  @media(max-width:620px){.view-drawer{width:100%}.view-grid{grid-template-columns:1fr}}


  body.modal-open{overflow:hidden;}
  .view-overlay.open{display:flex !important;}


  /* FIX navegación: el panel de ver no tapa el sidebar en escritorio */
  @media(max-width:900px){
    .view-overlay{
      left:0;
      width:100vw;
      z-index:10000;
    }
  }

  /* seguridad para que los overlays no bloqueen el menú cuando están cerrados */
  .overlay,.view-overlay,.sidebar-overlay{pointer-events:none}
  .overlay.open,.view-overlay.open,.sidebar-overlay.open{pointer-events:auto}

  /* ── BUSCADOR LOCAL EN CONTRATACIÓN ── */
  .card-head-search {
    gap: 14px;
    align-items: center;
  }

  .contract-search-wrap {
    flex: 1;
    min-width: 280px;
    display: flex;
    align-items: center;
    gap: 8px;
    background: #f7fbf8;
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 11px 14px;
    transition: border-color .2s, box-shadow .2s, background .2s;
  }

  .contract-search-wrap:focus-within {
    border-color: #b6dfc4;
    background: #ffffff;
    box-shadow: 0 0 0 3px rgba(45,223,110,0.07);
  }

  .contract-search-wrap svg {
    width: 16px;
    height: 16px;
    stroke: var(--text-soft);
    fill: none;
    stroke-width: 1.9;
    flex-shrink: 0;
  }

  .contract-search-wrap input {
    width: 100%;
    background: transparent;
    border: none;
    outline: none;
    font-family: 'DM Sans', sans-serif;
    font-size: 13.5px;
    color: var(--text);
  }

  .contract-search-wrap input::placeholder {
    color: var(--text-soft);
  }

  @media(max-width: 900px) {
    .card-head-search {
      flex-direction: column;
      align-items: stretch;
    }

    .contract-search-wrap {
      width: 100%;
      min-width: 100%;
    }

    .card-head-search .filters {
      width: 100%;
      flex-wrap: wrap;
    }

    .card-head-search .filter-sel {
      flex: 1;
      min-width: 150px;
    }
  }
  /* ── FILTRO TIPO TRABAJADORES PARA CONTRATACIÓN ── */
  .contratos-filter-bar {
    background: var(--white);
    border: 1px solid var(--border);
    border-radius: 14px;
    padding: 14px 18px;
    display: flex;
    align-items: flex-end;
    gap: 12px;
    flex-wrap: wrap;
    box-shadow: var(--shadow);
  }

  .contratos-filter-bar .filter-group {
    display: flex;
    flex-direction: column;
    gap: 4px;
  }

  .contratos-filter-bar .filter-search-main {
    flex: 1;
    min-width: 360px;
  }

  .contratos-filter-bar .filter-label {
    font-size: 10.5px;
    font-weight: 700;
    color: var(--text-soft);
    text-transform: uppercase;
    letter-spacing: .5px;
  }

  .contratos-filter-bar .filter-label-hidden {
    visibility: hidden;
  }

  .contratos-filter-bar .search-wrap {
    width: 100%;
    height: 40px;
    display: flex;
    align-items: center;
    gap: 8px;
    background: #ffffff;
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 9px 14px;
    transition: border-color .2s, box-shadow .2s;
  }

  .contratos-filter-bar .search-wrap:focus-within {
    border-color: #b6dfc4;
    box-shadow: 0 0 0 3px rgba(45,223,110,0.07);
  }

  .contratos-filter-bar .search-wrap svg {
    width: 15px;
    height: 15px;
    stroke: var(--text-soft);
    fill: none;
    stroke-width: 1.8;
    flex-shrink: 0;
  }

  .contratos-filter-bar .search-wrap input {       
    width: 100%;
    background: none;
    border: none;
    outline: none;
    font-size: 13.5px;
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
  }

  .contratos-filter-bar .search-wrap input::placeholder {
    color: var(--text-soft);
  }

  .contratos-filter-bar .filter-select {
    height: 40px;
    background: #ffffff;
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 0 32px 0 12px;
    font-size: 13px;
    color: var(--text-mid);
    font-family: 'DM Sans', sans-serif;
    cursor: pointer;
    appearance: none;
    min-width: 170px;
  }

  .contratos-filter-bar .filter-select:focus {
    outline: none;
    border-color: #b6dfc4;
  }

  .contratos-filter-bar .filter-buttons {
    display: flex;
    gap: 8px;
  }

  .contratos-filter-bar .btn-filter {
    display: flex;
    align-items: center;
    gap: 6px;
    height: 40px;
    background: #ffffff;
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 0 16px;
    font-size: 13px;
    color: var(--text-mid);
    cursor: pointer;
    transition: all .2s;
    white-space: nowrap;
    font-family: 'DM Sans', sans-serif;
  }

  .contratos-filter-bar .btn-filter:hover {
    border-color: #b6dfc4;
    background: #f0f8f3;
  }

  .contratos-filter-bar .btn-filter svg {
    width: 14px;
    height: 14px;
    stroke: currentColor;
    fill: none;
    stroke-width: 1.8;
  }

  .contratos-filter-bar .btn-clear {
    color: #dc2626;
    border-color: #fecaca;
  }

  .contratos-filter-bar .btn-clear:hover {
    background: #fff1f2;
    border-color: #fca5a5;
  }

  @media(max-width:900px) {
    .contratos-filter-bar {
      align-items: stretch;
    }

    .contratos-filter-bar .filter-search-main {
      min-width: 100%;
    }

    .contratos-filter-bar .filter-group {
      flex: 1;
      min-width: 150px;
    }

    .contratos-filter-bar .filter-buttons-group {
      min-width: 100%;
    }

    .contratos-filter-bar .filter-buttons {
      width: 100%;
    }

    .contratos-filter-bar .btn-filter {
      flex: 1;
      justify-content: center;
    }
  }

  /* ── FONDO DE TABLA CONTRATACIÓN ── */
  .contratos-table-card {
    background: var(--white);
