  .contratos-table-card table {
    background: var(--white);
  }

  .contratos-table-card thead tr {
    background: #f7fbf8;
  }

  .contratos-table-card tbody tr {
    background: var(--white);
  }

  .contratos-table-card tbody tr:hover {
    background: #f7fbf8;
  }


      .field-help{
