  <script>  
  const contratos = <?= $contratosJson ?: '[]' ?>;  
  const trabajadores = <?= $trabajadoresJson ?: '[]' ?>;

  let wizardPasoContrato = 1;

  function textoSelect(id) {
    const el = $(id);
    if (!el) return '';
    const opt = el.options ? el.options[el.selectedIndex] : null;
    return opt ? opt.textContent.trim() : (el.value || '').trim();
  }

  function setWizardPasoContrato(paso) {
    wizardPasoContrato = Math.max(1, Math.min(3, Number(paso) || 1));
    document.querySelectorAll('.wizard-panel').forEach(function(panel, index){
      panel.classList.toggle('active', index + 1 === wizardPasoContrato);
    });
    document.querySelectorAll('[data-step-indicator]').forEach(function(step){
      const n = Number(step.dataset.stepIndicator);
      step.classList.toggle('active', n === wizardPasoContrato);
      step.classList.toggle('done', n < wizardPasoContrato);
    });
    const back = $('btnWizardBack');
    const next = $('btnWizardNext');
    const save = $('btnGuardarContrato');
    if (back) back.style.display = wizardPasoContrato === 1 ? 'none' : 'inline-flex';
    if (next) next.style.display = wizardPasoContrato === 3 ? 'none' : 'inline-flex';
    if (save) save.style.display = wizardPasoContrato === 3 ? 'inline-flex' : 'none';
    if (wizardPasoContrato === 3) actualizarRevisionContrato();
  }

  function validarPasoContrato(paso) {
    if (paso === 1) {
      seleccionarTrabajadorBuscado();
      if (!$('id_trabajador')?.value) {
        alert('Selecciona un trabajador válido y disponible de la lista.');
        $('buscar_trabajador_contrato')?.focus();
        return false;
      }
      for (const id of ['id_area', 'id_cargo']) {
        const el = $(id);
        if (el && !el.value) {
          alert('Completa área y cargo antes de continuar.');
          el.focus();
          return false;
        }
      }
    }
    if (paso === 2) {
      for (const id of ['id_tipos_contrato', 'fecha_inicio', 'salario_base_view']) {
        const el = $(id);
        if (el && !String(el.value || '').trim()) {
          alert('Completa las condiciones obligatorias antes de revisar.');
          el.focus();
          return false;
        }
      }
    }
    return true;
  }

  function wizardSiguiente() {
    if (!validarPasoContrato(wizardPasoContrato)) return;
    setWizardPasoContrato(wizardPasoContrato + 1);
  }

  function wizardAnterior() {
    setWizardPasoContrato(wizardPasoContrato - 1);
  }

  function detectarPaqueteContrato() {
    const cargo = textoSelect('id_cargo');
    const cargoVal = $('id_cargo')?.value || '';
    const pack = $('contractPackage');
    const text = $('packageCargoText');
    if (pack) pack.classList.toggle('show', !!cargoVal);
    if (text) text.textContent = cargoVal ? ('Para el cargo: ' + cargo) : 'Selecciona un cargo para preparar los documentos.';
  }

  function actualizarRevisionContrato() {
    setText('reviewTrabajador', $('buscar_trabajador_contrato')?.value || 'Sin selecciónar');
    setText('reviewCargo', textoSelect('id_cargo') || 'Sin selecciónar');
    setText('reviewTipo', textoSelect('id_tipos_contrato') || 'Sin selecciónar');
    setText('reviewInicio', fechaVista($('fecha_inicio')?.value || ''));
    setText('reviewSalario', moneyCOP(limpiarNumero($('salario_base_view')?.value || '0')));
  }
  function $(id){ return document.getElementById(id); }

  function toggleSidebar(){
    $('sidebar')?.classList.toggle('open');
    $('sidebarOverlay')?.classList.toggle('open');
  }

  function closeSidebar(){
    $('sidebar')?.classList.remove('open');
    $('sidebarOverlay')?.classList.remove('open');
  }

  function toggleProfile(){
    $('profileDropdown')?.classList.toggle('open');
  }

  document.addEventListener('click', function(e){
    const wrap = $('profileWrap');
    if (wrap && !wrap.contains(e.target)) {
      $('profileDropdown')?.classList.remove('open');
    }
  });

  function abrirModalContrato(){
    setWizardPasoContrato(1);
    detectarPaqueteContrato();
    $('overlayContrato')?.classList.add('open');
  }

  function cerrarModalContrato(){
    $('overlayContrato')?.classList.remove('open');
  }

  function setValue(id, value){
    const el = $(id);
    if (el) el.value = value ?? '';
  }

  function setDisabledForm(disabled){
    const form = $('formContrato');
    if (!form) return;

    form.querySelectorAll('input, select, textarea').forEach(el => {
      if (el.type !== 'hidden') {
        el.disabled = disabled;
        if (el.tagName === 'TEXTAREA' || el.tagName === 'INPUT') {
          el.readOnly = disabled;
        }
      }
    });

    document.querySelectorAll('#trabajadorResultados .trabajador-option, #btnToggleTrabajadores').forEach(function(el){
      el.disabled = disabled;
    });

    const btn = $('btnGuardarContrato');
    if (btn) btn.style.display = disabled ? 'none' : 'inline-flex';
  }

  function normalizarTextoBusqueda(texto) {
    return (texto || '')
      .toString()
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .trim();
  }

  function etiquetaTrabajador(t) {
    if (!t) return '';
    const nombre = `${t.nombres || ''} ${t.apellidos || ''}`.replace(/\s+/g, ' ').trim();
    const documento = t.numero_documento || '';
    return documento ? `${nombre} · ${documento}` : nombre;
  }

  function trabajadorPorId(id) {
    return trabajadores.find(t => String(t.id_trabajador) === String(id));
  }

  function opcionesTrabajador() {
    return Array.from(document.querySelectorAll('#trabajadorResultados .trabajador-option'));
  }

  function ocultarOpcionesTrabajador() {
    const resultados = $('trabajadorResultados');
    if (resultados) resultados.hidden = true;
  }

  function mostrarOpcionesTrabajador(mostrarTodas = false) {
    const input = $('buscar_trabajador_contrato');
    const resultados = $('trabajadorResultados');
    const empty = $('trabajadorEmpty');

    if (!input || !resultados) return;

    const q = normalizarTextoBusqueda(input.value);
    const opciones = opcionesTrabajador();
    let visibles = 0;

    opciones.forEach(function(opcion) {
      const texto = normalizarTextoBusqueda(opcion.dataset.label || opcion.textContent || '');
      const mostrar = mostrarTodas || (q.length > 0 && texto.includes(q));

      opcion.hidden = !mostrar;
      if (mostrar) visibles++;
    });

    if (empty) empty.hidden = visibles !== 0;

    resultados.hidden = !(mostrarTodas || q.length > 0);
  }

  function aplicarTrabajadorSeleccionado(opcion) {
    const input = $('buscar_trabajador_contrato');
    const hidden = $('id_trabajador');       

    if (!input || !hidden || !opcion) return;

    input.value = opcion.dataset.label || '';
    input.dataset.selectedLabel = input.value;
    hidden.value = opcion.dataset.id || '';

    const area = opcion.dataset.area || '';
    const cargo = opcion.dataset.cargo || '';

    if (area && area !== '0') setValue('id_area', area);
    if (cargo && cargo !== '0') setValue('id_cargo', cargo);
    detectarPaqueteContrato();

    ocultarOpcionesTrabajador();
  }

  function seleccionarTrabajadorBuscado() {
    const input = $('buscar_trabajador_contrato');
    const hidden = $('id_trabajador');

    if (!input || !hidden) return;

    const valor = normalizarTextoBusqueda(input.value);

    if (!valor) {
      hidden.value = '';
      input.dataset.selectedLabel = '';
      return;
    }

    const opcion = opcionesTrabajador()
      .find(opt => normalizarTextoBusqueda(opt.dataset.label || '') === valor);

    if (!opcion) {
      // Si estamos editando/verificando un contrato existente, el trabajador puede no estar
      // en la lista de disponibles porque ya tiene contrato vigente. En ese caso no se borra.
      if (hidden.value && normalizarTextoBusqueda(input.dataset.selectedLabel || '') === valor) {
        return;
      }

      hidden.value = '';
      return;
    }

    aplicarTrabajadorSeleccionado(opcion);
  }

  function sincronizarTrabajador() {
    seleccionarTrabajadorBuscado();
  }

  function limpiarFormulario(){
    const form = $('formContrato');
    if (form) form.reset();

    setValue('accion', 'nuevo');
    setValue('contrato_id', '');
    setValue('id_trabajador', '');
    setValue('buscar_trabajador_contrato', '');
    const inputTrabajadorLimpiar = $('buscar_trabajador_contrato');
    if (inputTrabajadorLimpiar) inputTrabajadorLimpiar.dataset.selectedLabel = '';
    ocultarOpcionesTrabajador();
    setValue('salario_base', '');
    setValue('auxilio_transporte', '0');
    setValue('salario_base_view', '');
    setValue('auxilio_transporte_view', '0');
    setWizardPasoContrato(1);
    detectarPaqueteContrato();

    const inputTrabajador = $('buscar_trabajador_contrato');
    if (inputTrabajador) inputTrabajador.dataset.selectedLabel = '';

    setDisabledForm(false);
  }

  function nuevoContrato(){
    limpiarFormulario();
    $('modalContratoTitulo').textContent = 'Nueva contratación';
    $('btnGuardarContrato').textContent = 'Guardar contratación';
    abrirModalContrato();
  }

  function llenarContrato(idx){
    const c = contratos[idx];
    if (!c) return null;

    setValue('contrato_id', c.id_contrato || '');
    setValue('id_trabajador', c.id_trabajador || '');

    const t = trabajadorPorId(c.id_trabajador);
    const label = etiquetaTrabajador(t) || `${c.nombres || ''} ${c.apellidos || ''}`.replace(/\s+/g, ' ').trim() + (c.numero_documento ? ` · ${c.numero_documento}` : '');
    setValue('buscar_trabajador_contrato', label.trim());

    const inputTrabajador = $('buscar_trabajador_contrato');
    if (inputTrabajador) inputTrabajador.dataset.selectedLabel = label.trim();
    ocultarOpcionesTrabajador();

    setValue('id_area', c.id_area || c.id_area_final || '');
    setValue('id_cargo', c.id_cargo || c.id_cargo_final || '');
    setValue('jefe_inmediato', c.jefe_inmediato || '');
    setValue('fecha_ingreso', c.fecha_ingreso || '');
    setValue('id_tipos_contrato', c.id_tipos_contrato || '');
    setValue('jornada', c.jornada || 'Completa (46h/sem)');
    setValue('modalidad', c.modalidad || 'Presencial');
    setValue('fecha_inicio', c.fecha_inicio || '');
    setValue('fecha_fin', c.fecha_fin || '');
    setValue('periodo_prueba', c.periodo_prueba || 'Sin periodo');
    setValue('observaciones', c.observaciones || '');

    setValue('salario_base', c.salario_base || '');
    setValue('auxilio_transporte', c.auxilio_transporte || '0');
    setValue('salario_base_view', formatearMiles(c.salario_base || ''));
    setValue('auxilio_transporte_view', formatearMiles(c.auxilio_transporte || '0'));
    detectarPaqueteContrato();

    return c;
  }

  function numeroNomina(valor){
    const limpio = String(valor ?? '0').replace(/[^\d.-]/g, '');
    const n = Number(limpio);
    return Number.isFinite(n) ? n : 0;
  }

  function moneyCOP(valor){
    return '$' + Math.round(numeroNomina(valor)).toLocaleString('es-CO');
  }

  function fechaVista(fecha){
    if (!fecha || fecha === '0000-00-00') return 'Indefinido';
    const partes = String(fecha).split('-');
    if (partes.length === 3) return partes[2] + '/' + partes[1] + '/' + partes[0];
    return fecha;
  }

  function statusClassJS(estado){
    if (estado === 'Activo') return 'status-active';
    if (estado === 'Por vencer') return 'status-warning';
    if (estado === 'Vencido' || estado === 'Inactivo') return 'status-danger';
    if (estado === 'Terminado') return 'status-muted';
    return 'status-muted';
  }

  function setText(id, value){
    const el = document.getElementById(id);
    if (el) el.textContent = value ?? '';
  }

  function abrirVistaContratoPorId(idContrato){
    const id = Number(idContrato);

    if (!Number.isFinite(id) || id <= 0) {
      alert('No se pudo abrir el contrato. ID inválido.');
      return false;
    }

    if (typeof contratos === 'undefined' || !Array.isArray(contratos)) {
      alert('No se pudo abrir el contrato. La información no está disponible.');
      return false;
    }

    const idx = contratos.findIndex(function(c){
      return Number(c.id_contrato) === id;
    });

    if (idx === -1) {
      alert('No se encontró el contrato seleccionado.');
      return false;
    }

    return abrirVistaContrato(idx);
  }

  function abrirVistaContrato(idx){
    idx = Number(idx);

    if (!Number.isInteger(idx) || idx < 0) {
      alert('No se pudo abrir el contrato. Índice inválido.');
      return false;
    }

    if (typeof contratos === 'undefined' || !Array.isArray(contratos)) {
      alert('No se pudo abrir el contrato. La información no está disponible.');
      return false;
    }

    const c = contratos[idx];
    if (!c) {
      alert('No se encontró el contrato seleccionado.');
      return false;
    }

    document.querySelectorAll('#tablaContratos tbody tr').forEach(function(row){
      row.classList.remove('selected');
    });

    const row = document.querySelector('#tablaContratos tbody tr[data-index="' + idx + '"]');
    if (row) row.classList.add('selected');

    const salarioBase = numeroNomina(c.salario_base || 0);
    const auxilio = numeroNomina(c.auxilio_transporte || 0);
    const salud = Math.round(salarioBase * 0.04);
    const pension = Math.round(salarioBase * 0.04);
    const totalDevengado = salarioBase + auxilio;
    const totalDeducciones = salud + pension;
    const netoPagar = totalDevengado - totalDeducciones;

    setText('verIniciales', c.iniciales || 'TR');
    setText('verNombre', c.nombre_completo || 'Trabajador');
    setText('verSub', 'ID ' + String(c.id_trabajador || 0).padStart(4, '0') + ' · ' + (c.area || 'Sin área'));
    setText('verCargo', c.cargo || 'Sin cargo');
    setText('verArea', c.area || 'Sin área');
    setText('verTipoContrato', c.tipo_contrato || 'Sin tipo');
    setText('verJornada', c.jornada || '—');
    setText('verModalidad', c.modalidad || '—');
    setText('verFechaInicio', fechaVista(c.fecha_inicio));
    setText('verFechaFin', fechaVista(c.fecha_fin));
    setText('verPeriodoPrueba', c.periodo_prueba || 'Sin periodo');
    setText('verObservaciones', c.observaciones || 'Sin observaciones.');
    const docCargo = (c.cargo || 'Cargo').replace(/\\s+/g, '_');
    setText('docContratoMeta', 'Contrato_Laboral_' + docCargo + '.docx');
    setText('docPerfilMeta', 'Perfil_Cargo_' + docCargo + '.docx');
    setText('docInducciónMeta', 'Inducción_' + docCargo + '.docx');

    const estado = c.estado_mostrar || c.estado || 'Sin estado';
    const estadoEl = document.getElementById('verEstado');
    if (estadoEl) {
      estadoEl.textContent = estado;
      estadoEl.className = 'status-pill ' + statusClassJS(estado);
    }

    setText('verSalarioBase', moneyCOP(salarioBase));
    setText('verAuxilio', moneyCOP(auxilio));
    setText('verTotalDevengado', moneyCOP(totalDevengado));
    setText('verSalud', '-' + moneyCOP(salud));
    setText('verPension', '-' + moneyCOP(pension));
    setText('verTotalDeducciones', '-' + moneyCOP(totalDeducciones));
    setText('verNetoPagar', moneyCOP(netoPagar));

    const overlay = document.getElementById('overlayVerContrato');
    if (overlay) overlay.classList.add('open');

    document.body.classList.add('modal-open');
    return false;
  }

  function verContrato(idx){
    return abrirVistaContrato(idx);
  }

  function cerrarVistaContrato(){
    const overlay = document.getElementById('overlayVerContrato');
    if (overlay) overlay.classList.remove('open');

    document.body.classList.remove('modal-open');

    document.querySelectorAll('#tablaContratos tbody tr').forEach(function(row){
      row.classList.remove('selected');
    });
  }

  function editarContrato(idx){
    limpiarFormulario();
    const c = llenarContrato(idx);
    if (!c) return;

    setValue('accion', 'actualizar');
    $('modalContratoTitulo').textContent = 'Editar contratación';
    $('btnGuardarContrato').textContent = 'Guardar cambios';
    setDisabledForm(false);
    abrirModalContrato();
  }

  function renovarContrato(idx){
    limpiarFormulario();
    const c = llenarContrato(idx);
    if (!c) return;

    setValue('accion', 'renovar');
    $('modalContratoTitulo').textContent = 'Renovar contrato';
    $('btnGuardarContrato').textContent = 'Guardar renovación';
    setValue('fecha_inicio', new Date().toISOString().slice(0,10));
    setValue('fecha_fin', '');
    setDisabledForm(false);
    abrirModalContrato();
  }

  function abrirTerminar(idContrato, nombre){
    setValue('terminar_contrato_id', idContrato);
    const nombreEl = $('terminar_nombre');
    if (nombreEl) nombreEl.textContent = nombre || 'este trabajador';
    $('overlayTerminar')?.classList.add('open');
  }

  function cerrarTerminar(){
    $('overlayTerminar')?.classList.remove('open');
  }

  function normalizarTextoContrato(texto) {
    return (texto || '')
      .toString()
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .trim();
  }

  function filtrarTabla(){
    const q = normalizarTextoContrato(
      $('busquedaContratoLocal')?.value ||
      $('busquedaGlobal')?.value ||
      ''
    );

    const estado = $('filtroEstado')?.value || '';
    const area = $('filtroArea')?.value || '';

    document.querySelectorAll('#tablaContratos tbody tr').forEach(tr => {
      if (!tr.dataset) return;

      const textoFila = normalizarTextoContrato((tr.dataset.texto || '') + ' ' + tr.innerText);
      const areaFila = normalizarTextoContrato(tr.dataset.area || '');
      const areaFiltro = normalizarTextoContrato(area);

      const coincideTexto = !q || textoFila.includes(q);
      const coincideEstado = !estado || (tr.dataset.estado || '') === estado;
      const coincideArea = !area || areaFila.includes(areaFiltro);

      tr.style.display = (coincideTexto && coincideEstado && coincideArea) ? '' : 'none';
    });
  }

  function limpiarNumero(valor){
    return String(valor || '').replace(/[^\d]/g, '');
  }

  function formatearMiles(valor){
    const limpio = limpiarNumero(valor);
    if (!limpio) return '';
    return new Intl.NumberFormat('es-CO').format(Number(limpio));
  }

  function sincronizarMoneyInput(viewId, hiddenId){
    const view = $(viewId);
    const hidden = $(hiddenId);
    if (!view || !hidden) return;

    view.addEventListener('input', function(){
      const limpio = limpiarNumero(view.value);
      view.value = formatearMiles(limpio);
      hidden.value = limpio;
    });

    hidden.value = limpiarNumero(view.value);
    view.value = formatearMiles(view.value);
  }

  sincronizarMoneyInput('salario_base_view', 'salario_base');
  sincronizarMoneyInput('auxilio_transporte_view', 'auxilio_transporte');

  const inputTrabajadorContrato = $('buscar_trabajador_contrato');
  const btnToggleTrabajadores = $('btnToggleTrabajadores');
  const resultadosTrabajador = $('trabajadorResultados');

  if (inputTrabajadorContrato) {
    inputTrabajadorContrato.addEventListener('input', function(){
      const hidden = $('id_trabajador');

      if (normalizarTextoBusqueda(inputTrabajadorContrato.value) !== normalizarTextoBusqueda(inputTrabajadorContrato.dataset.selectedLabel || '')) {
        if (hidden) hidden.value = '';
      }

      mostrarOpcionesTrabajador(false);
    });

    inputTrabajadorContrato.addEventListener('focus', function(){
      // No se abre automáticamente al enfocar; solo al escribir o tocar la flecha.
      if (inputTrabajadorContrato.value.trim() !== '') {
        mostrarOpcionesTrabajador(false);
      }
    });
  }

  if (btnToggleTrabajadores) {
    btnToggleTrabajadores.addEventListener('click', function(){
      if (resultadosTrabajador && !resultadosTrabajador.hidden) {
        ocultarOpcionesTrabajador();
      } else {
        mostrarOpcionesTrabajador(true);
        inputTrabajadorContrato?.focus();
      }
    });
  }

  document.querySelectorAll('#trabajadorResultados .trabajador-option').forEach(function(opcion){
    opcion.addEventListener('click', function(){
      aplicarTrabajadorSeleccionado(opcion);
    });
  });

  document.addEventListener('click', function(e){
    const box = $('trabajadorSearchBox');
    if (box && !box.contains(e.target)) {
      ocultarOpcionesTrabajador();
    }
  });

  const inputContratoLocal = $('busquedaContratoLocal');
  const areaContratoLocal = $('filtroArea');
  const estadoContratoLocal = $('filtroEstado');
  const btnFiltrarContratos = $('btnFiltrarContratos');
  const btnLimpiarContratos = $('btnLimpiarContratos');

  if (inputContratoLocal) inputContratoLocal.addEventListener('input', filtrarTabla);
  if (areaContratoLocal) areaContratoLocal.addEventListener('change', filtrarTabla);
  if (estadoContratoLocal) estadoContratoLocal.addEventListener('change', filtrarTabla);
  $('id_cargo')?.addEventListener('change', detectarPaqueteContrato);
  ['buscar_trabajador_contrato','id_tipos_contrato','fecha_inicio','salario_base_view'].forEach(function(id){
    $(id)?.addEventListener('input', actualizarRevisionContrato);
    $(id)?.addEventListener('change', actualizarRevisionContrato);
  });
  setWizardPasoContrato(1);
  if (btnFiltrarContratos) btnFiltrarContratos.addEventListener('click', filtrarTabla);

  if (btnLimpiarContratos) {
    btnLimpiarContratos.addEventListener('click', function(){
      if (inputContratoLocal) inputContratoLocal.value = '';
      if (areaContratoLocal) areaContratoLocal.value = '';
      if (estadoContratoLocal) estadoContratoLocal.value = '';
      filtrarTabla();
    });
  }

  const formContrato = $('formContrato');
  if (formContrato) {
    formContrato.addEventListener('submit', function(e){
      seleccionarTrabajadorBuscado();

      if (!$('id_trabajador')?.value) {
        e.preventDefault();
        alert('Selecciona un trabajador válido y disponible de la lista.');
        $('buscar_trabajador_contrato')?.focus();
        return;
      }

      const salarioView = $('salario_base_view');
      const auxilioView = $('auxilio_transporte_view');

      if ($('salario_base')) $('salario_base').value = limpiarNumero(salarioView?.value || '');
      if ($('auxilio_transporte')) $('auxilio_transporte').value = limpiarNumero(auxilioView?.value || '0') || '0';
    });
  }

  document.addEventListener('click', function(e){
    const btnCloseView = e.target.closest('[data-close-ver-contrato]');
    if (btnCloseView) {
      e.preventDefault();
      cerrarVistaContrato();
      return;
    }

    const btnVer = e.target.closest('.js-ver-contrato, [data-ver-contrato]');
    if (btnVer) {
      e.preventDefault();
      e.stopPropagation();

      const idx = parseInt(btnVer.dataset.verContrato || '', 10);
      if (!Number.isNaN(idx)) {
        abrirVistaContrato(idx);
        return;
      }

      abrirVistaContratoPorId(btnVer.dataset.id);
    }
  });

  $('overlayVerContrato')?.addEventListener('click', function(e){
    if (e.target === this) cerrarVistaContrato();
  });

  $('overlayContrato')?.addEventListener('click', function(e){
    if (e.target === this) cerrarModalContrato();
  });

  $('overlayTerminar')?.addEventListener('click', function(e){
    if (e.target === this) cerrarTerminar();
  });

  /* Seguridad extra: los enlaces del menú navegan aunque haya un estado visual raro */
  document.querySelectorAll('.sidebar-nav a.nav-item, .nav-logout').forEach(function(link){
    link.addEventListener('click', function(){
      cerrarVistaContrato();
      closeSidebar();
    });
  });

  document.addEventListener('keydown', function(e){
    if (e.key === 'Escape') {
      cerrarVistaContrato();
      cerrarModalContrato();
      cerrarTerminar();
      closeSidebar();
    }

    if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'k') {
      e.preventDefault();
      $('busquedaGlobal')?.focus();
    }
  });
  </script>
  </body>
  </html>